(function($){$(function(){var $select=$(".fq-promo-products-select");if(!$select.length||typeof $.fn.select2!=="function"){return}$select.each(function(){var $field=$(this);var restUrl=$field.data("rest-url");var restNonce=$field.data("rest-nonce");var placeholder=$field.data("placeholder")||"Buscar productos...";$field.select2({width:"100%",placeholder:placeholder,allowClear:false,ajax:{url:restUrl,dataType:"json",delay:250,headers:{"X-WP-Nonce":restNonce},data:function(params){return{search:params.term||"",page:params.page||1}},processResults:function(data){return{results:data.results||[],pagination:data.pagination||{more:false}}},cache:true},minimumInputLength:0})})})})(jQuery);
